        raise ValueError("Payload too long")

    payload = data[3:3+length]
    checksum = sum(data[:3+length]) % 256
    if checksum != data[3+length]:
        raise ValueError("Checksum mismatch")

    return {'cmd': cmd, 'payload': payload}
